import { Account } from '@domain/account';
import { ActionPageDetails, ActionPageType, PageTypes } from '@domain/actionPages';
import {
  useActivateActionPage,
  useArchiveActionPage,
  useUpdateActionPage,
} from '@state/action_pages';
import { useCreateActionPage } from '@state/action_pages/mutations/useCreateActionPage';
import { useGetAllCustomDomains } from '@state/customDomains';
import { useToast } from '@ui/components/Toast';
import { getActionPageURLByString } from '@utils';
import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';

export const useActionPagesActions = ({ currentAccount }: { currentAccount?: Account }) => {
  const { t } = useTranslation('actionPages');
  const navigate = useNavigate();

  const { showToast } = useToast();
  const { customDomains } = useGetAllCustomDomains({});

  const { activateActionPage } = useActivateActionPage({
    onError: () => {
      showToast({
        message: t('activate.error.message'),
        variant: 'error',
      });
    },
    onSuccess: () => {
      showToast({
        message: t('activate.success.message'),
        variant: 'success',
      });
    },
  });

  const onActivate = useCallback(
    (actionPageId: string) => {
      activateActionPage({ accountId: currentAccount?.id, id: actionPageId });
    },
    [currentAccount, activateActionPage]
  );

  const { archiveActionPage } = useArchiveActionPage({
    onError: () => {
      showToast({
        message: t('archive.error.message'),
        variant: 'error',
      });
    },
    onSuccess: () => {
      showToast({
        message: t('archive.success.message'),
        variant: 'success',
      });
    },
  });

  const onArchive = useCallback(
    (actionPageId: string) => {
      archiveActionPage({ accountId: currentAccount?.id, id: actionPageId });
    },
    [archiveActionPage, currentAccount]
  );

  const onCreate = useCallback(
    (pageType: PageTypes) => {
      if (pageType === PageTypes.Event) {
        navigate({
          pathname: `/accounts/${currentAccount?.id}/builder/new-event`,
        });
      } else {
        navigate({
          pathname: `/accounts/${currentAccount?.id}/action_pages/new/edit`,
          search: `?type=${
            pageType === PageTypes.Lead
              ? 'lead'
              : pageType === PageTypes.Storefront
                ? 'storefront'
                : 'donation'
          }`,
        });
      }
    },
    [currentAccount?.id, navigate]
  );

  const onClone = useCallback(
    (actionPageId: string, pageType: ActionPageType) => {
      if (pageType === 'event') {
        navigate({
          pathname: `/accounts/${currentAccount?.id}/builder/new-event`,
          search: `?templateId=${actionPageId}`,
        });
      } else {
        navigate({
          pathname: `/accounts/${currentAccount?.id}/action_pages/new/edit`,
          search: `?cloneFrom=${actionPageId}`,
        });
      }
    },
    [navigate, currentAccount?.id]
  );

  const onEdit = useCallback(
    (actionPageId: string, isEvent: boolean) => {
      navigate({
        pathname: isEvent
          ? `/accounts/${currentAccount?.id}/builder/${actionPageId}`
          : `/accounts/${currentAccount?.id}/action_pages/${actionPageId}/edit`,
      });
    },
    [currentAccount?.id, navigate]
  );

  const onView = useCallback(
    (apSlug: string) => {
      if (currentAccount) {
        window.open(
          getActionPageURLByString(currentAccount.slug, apSlug, customDomains, null),
          '__blank'
        );
      }
    },
    [currentAccount, customDomains]
  );

  const onViewSubmissions = useCallback(
    (actionPageId: string) => {
      navigate({
        pathname: `/accounts/${currentAccount?.id}/submissions`,
        search: `actionPageId=${actionPageId}`,
      });
    },
    [currentAccount?.id, navigate]
  );

  const { updateActionPage } = useUpdateActionPage({
    onError: () => {
      showToast({
        message: t('update.error.message'),
        variant: 'error',
      });
    },
    onSuccess: () => {
      showToast({
        message: t('update.success.message'),
        variant: 'success',
      });
    },
  });

  const { createActionPage } = useCreateActionPage({
    onError: () => {
      showToast({
        message: t('create.error.message'),
        variant: 'error',
      });
    },
    onSuccess: () => {
      showToast({
        message: t('create.success.message'),
        variant: 'success',
      });
    },
  });

  const onUpdate = useCallback(
    (actionPage: ActionPageDetails) => {
      return actionPage.id === 'new' ? createActionPage(actionPage) : updateActionPage(actionPage);
    },
    [createActionPage, updateActionPage]
  );

  return {
    onActivate,
    onArchive,
    onClone,
    onCreate,
    onEdit,
    onUpdate,
    onView,
    onViewSubmissions,
  };
};

